function stripCredentials(url) {
    const parsedUrl = new URL(url);
    const { protocol, hostname, pathname, search, hash } = parsedUrl;

    // Remove username and password from the hostname
    const usernameIndex = hostname.indexOf('@');
    if (usernameIndex !== -1) {
        parsedUrl.hostname = hostname.substring(usernameIndex + 1);
    }

    const passwordIndex = hostname.indexOf(':');
    if (passwordIndex !== -1) {
        parsedUrl.hostname = hostname.substring(0, passwordIndex);
    }

    return `${protocol}://${parsedUrl.hostname}${pathname}${search}${hash}`;
}

