You can use the `HttpClient` class in ASP.NET Core to create a proxy for another endpoint. Here's an example of how you can do this:

```csharp
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using System;
using System.Net.Http;
using System.Threading.Tasks;

public class ProxyMiddleware
{
    private readonly RequestDelegate _next;
    private readonly HttpClient _httpClient;

    public ProxyMiddleware(RequestDelegate next, IHttpClientFactory httpClientFactory)
    {
        _next = next;
        _httpClient = httpClientFactory.CreateClient();
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var originalUrl = context.Request.Headers["X-Original-Url"];
        if (!string.IsNullOrEmpty(originalUrl))
        {
            var request = new HttpRequestMessage(HttpMethod.Get, originalUrl);
            request.Headers.CopyFrom(context.Request.Headers);
            request.Content = await context.Request.ReadAsByteArrayAsync();

            var response = await _httpClient.SendAsync(request);
            context.Response.StatusCode = (int)response.StatusCode;
            await response.Content.CopyToAsync(context.Response.Body);
            return;
        }

        await _next(context);
    }
}
```

