```typescript
// src/hooks/useNotification.ts
import { useContext } from 'react';
import { NotificationContext } from '@/src/contexts/Notification.context';
import { notify } from '../helpers/notification.helpers';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const useNotification = (): {
  triggerNotification: (props: NotificationProps) => void;
} => {
  const notificationElem = useContext(NotificationContext);

  const triggerNotification = async (props: NotificationProps) => {
    if (!notificationElem) return;

    try {
      await notify(notificationElem, props);
    } catch (error) {
      console.error(error);
    }
  };

  return { triggerNotification };
};

export default useNotification;
